import re
from typing import Union, Optional


class ASTNode:
    def __init__(
        self,
        type: str,
        value: Optional[Union[int, float]] = None,
        op: Optional[str] = None,
        left: Optional["ASTNode"] = None,
        right: Optional["ASTNode"] = None,
        operand: Optional["ASTNode"] = None,
    ):
        self.type = type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand


def parse(expression: str) -> ASTNode:
    """Parse a mathematical expression into an Abstract Syntax Tree."""
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    # Remove whitespace
    expression = expression.replace(" ", "")

    # Tokenize the expression
    tokens = tokenize(expression)

    # Parse the expression
    try:
        result = parse_expression(tokens, 0)
        if result[1] < len(tokens):
            raise ValueError("Invalid expression")
        return result[0]
    except IndexError:
        raise ValueError("Invalid expression")


def tokenize(expression: str) -> list:
    """Convert expression string into tokens."""
    tokens = []
    i = 0
    while i < len(expression):
        if expression[i].isdigit() or expression[i] == ".":
            # Parse number
            num_str = ""
            while i < len(expression) and (
                expression[i].isdigit() or expression[i] == "."
            ):
                num_str += expression[i]
                i += 1
            tokens.append(
                ("NUMBER", float(num_str) if "." in num_str else int(num_str))
            )
        elif expression[i] in "+-*/()":
            if expression[i] == "-" and (i == 0 or expression[i - 1] in "(+-*/"):
                # This is a unary minus
                tokens.append(("UNARY_MINUS", "-"))
            else:
                tokens.append(("OPERATOR", expression[i]))
            i += 1
        else:
            raise ValueError(f"Invalid character: {expression[i]}")
    return tokens


def parse_expression(tokens: list, pos: int) -> tuple:
    """Parse expression with lowest precedence (addition and subtraction)."""
    return parse_binop(tokens, pos, 0)


def parse_binop(tokens: list, pos: int, min_precedence: int) -> tuple:
    """Parse binary operations with precedence."""
    if pos >= len(tokens):
        raise ValueError("Unexpected end of expression")

    # Parse left operand
    node, pos = parse_unary(tokens, pos)

    # Parse binary operators with higher precedence
    while pos < len(tokens):
        token_type, token_value = tokens[pos]
        if token_type != "OPERATOR":
            break

        precedence = get_precedence(token_value)
        if precedence < min_precedence:
            break

        # Parse right operand
        right_node, new_pos = parse_binop(tokens, pos + 1, precedence + 1)

        # Create binary operation node
        node = ASTNode("binop", op=token_value, left=node, right=right_node)
        pos = new_pos

    return node, pos


def parse_unary(tokens: list, pos: int) -> tuple:
    """Parse unary operations."""
    if pos < len(tokens):
        token_type, token_value = tokens[pos]
        if token_type == "UNARY_MINUS":
            # Parse the operand
            operand_node, new_pos = parse_unary(tokens, pos + 1)
            # Create unary operation node
            node = ASTNode("unary", op="-", operand=operand_node)
            return node, new_pos
        else:
            # Parse primary expression
            return parse_primary(tokens, pos)
    raise ValueError("Unexpected end of expression")


def parse_primary(tokens: list, pos: int) -> tuple:
    """Parse primary expressions (numbers, parentheses)."""
    if pos >= len(tokens):
        raise ValueError("Unexpected end of expression")

    token_type, token_value = tokens[pos]

    if token_type == "NUMBER":
        node = ASTNode("number", value=token_value)
        return node, pos + 1
    elif token_type == "OPERATOR" and token_value == "(":
        # Parse parenthesized expression
        node, new_pos = parse_expression(tokens, pos + 1)
        if new_pos >= len(tokens) or tokens[new_pos][1] != ")":
            raise ValueError("Unmatched parenthesis")
        return node, new_pos + 1
    else:
        raise ValueError("Invalid token in primary expression")


def get_precedence(op: str) -> int:
    """Get operator precedence."""
    if op in ["+", "-"]:
        return 1
    elif op in ["*", "/"]:
        return 2
    else:
        return -1


def evaluate(node: ASTNode) -> float:
    """Evaluate an AST node to a numeric result."""
    if node.type == "number":
        if node.value is None:
            raise ValueError("Invalid AST node: number node with no value")
        return float(node.value)
    elif node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Invalid AST node: binop node with missing operands")
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        if node.operand is None:
            raise ValueError("Invalid AST node: unary node with missing operand")
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
    raise ValueError("Invalid AST node type")
